from flask import Flask, session
from functools import wraps
import redis
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Connect to Redis server
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

def cache(expire_time):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Create a unique cache key based on function and arguments
            cache_key = f.__name__ + str(args) + str(kwargs)
            cached_value = redis_client.get(cache_key)
            
            if cached_value is not None:
                return cached_value.decode('utf-8')
            
            result = f(*args, **kwargs)
            # Store the result in Redis with an expiration time
            redis_client.setex(cache_key, expire_time, result.encode('utf-8'))
            return result
        return decorated_function
    return decorator

@app.route('/set_session/<user_id>')
def set_session(user_id):
    session['user_id'] = user_id
    return f"Session set for user: {user_id}"

@app.route('/get_session')
def get_session():
    user_id = session.get('user_id', 'Not Set')
    return f"Current User ID in Session: {user_id}"

@cache(expire_time=30)  # Cache the result for 30 seconds
def expensive_query(param):
    # Simulate an expensive database query
    time.sleep(2)
    return f"Cached Result for {param}"

@app.route('/expensive_query/<param>')
def run_expensive_query(param):
    result = expensive_query(param)
    return f"Result: {result}"

if __name__ == '__main__':
    app.run(debug=True)